mapper.select:
SELECT

FROM ai_business_object_relation
WHERE tenant_id = #{tenantId}
  AND id = #{id}
LIMIT 1

SELECT

FROM ai_business_object_relation
WHERE tenant_id = #{tenantId}
  AND suite_code = #{suiteCode}
  AND source_object_code = #{sourceObjectCode}
  AND status = 1
ORDER BY sort_order ASC, id ASC

SELECT COUNT(1)
FROM ai_business_object_relation
WHERE tenant_id = #{tenantId}
  AND suite_code = #{suiteCode}
  AND source_object_code = #{sourceObjectCode}
  AND target_object_code = #{targetObjectCode}
  AND relation_type = #{relationType}
  AND relation_name = #{relationName}

  AND id != #{excludeId}

